<template>
    <div>
         <img id="img1" class="img" src="../assets/8.png" >
         <img id='img2' class="img" src="../assets/7.png">
          <img id='img3' class="img" src="../assets/8.1.png">
          <button v-on:click="show()">1stimage</button>
          <button  v-on:click="show2()">2ndimage</button>
          <button  v-on:click="show3()">3rdimage</button>
          <p id="txt">helloworld</p>
    </div>
</template>

<script>
export default {

    methods:{
        show:function(){
            document.getElementById("img1").style.display="block";
            document.getElementById("img2").style.display="none";
            document.getElementById("img3").style.display="none";
        },
        show2:function(){
            document.getElementById("img2").style.display="block";
            document.getElementById("img1").style.display="none";
            document.getElementById("img3").style.display="none";
        },
        show3:function(){
            document.getElementById("img3").style.display="block";
              document.getElementById("img1").style.display="none";
            document.getElementById("img2").style.display="none";
        },
    }
}
</script>

<style scoped>
.img{
    width:200px;
    height:200px;
    display: none;
}


</style>